export async function getServiceForTsconfig(
    tsconfigPath: string,
    workspacePath: string,
    docContext: LanguageServiceDocumentContext
): Promise<LanguageServiceContainer> {
    if (tsconfigPath) {
        tsconfigPath = normalizePath(tsconfigPath);
    }
    const tsconfigPathOrWorkspacePath = tsconfigPath || workspacePath;
    const reloading = pendingReloads.has(tsconfigPath);

    let service: LanguageServiceContainer;

    if (reloading || !services.has(tsconfigPathOrWorkspacePath)) {
        if (reloading) {
            Logger.log('Reloading ts service at ', tsconfigPath, ' due to config updated');
            parsedTsConfigInfo.delete(tsconfigPath);
        } else {
            Logger.log('Initialize new ts service at ', tsconfigPath);
        }

        pendingReloads.delete(tsconfigPath);
        const newService = createLanguageService(tsconfigPath, workspacePath, docContext);
        services.set(tsconfigPathOrWorkspacePath, newService);
        service = await newService;
    } else {
        service = await services.get(tsconfigPathOrWorkspacePath)!;
    }

    if (pendingForAllServices.size > 0) {
        await Promise.all(pendingForAllServices);
    }

    return service;
}

export function getHoverInfo(
    document: Document,
    svelteDoc: SvelteDocument,
    position: Position
): Hover | null {
    const offset = svelteDoc.offsetAt(position);

    const offsetStart = Math.max(offset - 10, 0);
    const charactersAroundOffset = svelteDoc
        .getText()
        // use last 10 and next 10 characters, should cover 99% of all cases
        .substr(offsetStart, 20);
    const isSvelteTag = tagRegexp.test(charactersAroundOffset);

    if (inStyleOrScript(svelteDoc, position)) {
        return null;
    }

    if (isSvelteTag) {
        return getTagHoverInfoAtOffset(svelteDoc, offsetStart, charactersAroundOffset, offset);
    }

    const attributeContext = getAttributeContextAtPosition(document, position);

    if (!attributeContext || !attributeCanHaveEventModifier(attributeContext)) {
        return null;
    }

    const attributeOffset = svelteDoc.getText().lastIndexOf(attributeContext.name, offset);

    return getEventModifierHoverInfo(attributeContext, attributeOffset, offset);
}

private static create(
    originalDoc: Document,
    transpiled: string,
    originalTagInfo: TagInformation | null,
    transpiledTagInfo: TagInformation | null,
    processed: Processed[]
) {
    const sourceMapper =
        processed.length > 0
            ? SvelteFragmentMapper.createSourceMapper(processed, originalDoc)
            : new IdentityMapper(originalDoc.uri);

    if (originalTagInfo && transpiledTagInfo) {
        const sourceLength = originalTagInfo.container.end - originalTagInfo.container.start;
        const transpiledLength =
            transpiledTagInfo.container.end - transpiledTagInfo.container.start;
        const diff = sourceLength - transpiledLength;

        return new SvelteFragmentMapper(
            { end: transpiledTagInfo.container.end, diff },
            new FragmentMapper(originalDoc.getText(), originalTagInfo, originalDoc.uri),
            new FragmentMapper(transpiled, transpiledTagInfo, originalDoc.uri),
            sourceMapper
        );
    }

    return null;
}

private async mapReference(
    ref: ts.ReferencedSymbolEntry,
    context: ReferenceContext,
    snapshots: SnapshotMap,
    cancellationToken: CancellationToken | undefined
) {
    if (!context.includeDeclaration && ref.isDefinition) {
        return null;
    }

    const snapshot = await snapshots.retrieve(ref.fileName);

    if (cancellationToken?.isCancellationRequested) {
        return null;
    }

    if (isTextSpanInGeneratedCode(snapshot.getFullText(), ref.textSpan)) {
        return null;
    }

    // TODO we should deduplicate if we support finding references from multiple language service
    const location = convertToLocationForReferenceOrDefinition(snapshot, ref.textSpan);

    // Some references are in generated code but not wrapped with explicit ignore comments.
    // These show up as zero-length ranges, so filter them out.
    if (!hasNonZeroRange(location)) {
        return null;
    }

    return location;
}

// Check if we have a placeholder component
    const asyncComponent = args.asyncComponent as AsyncSvelteComponent & {
        loading?: Component<any, any>
        loadingParams?: Record<string, unknown>
    }
    if (args.loadingComponent) {
        asyncComponent.loading = args.loadingComponent
        asyncComponent.loadingParams = args.loadingParams || undefined
    }

    // Build the wrapped component
    // _sveltesparouter is defined as a read-only, non-enumerable, non-configurable property so callers can't tamper with the marker the router uses to detect wrapped routes
    const wrapped: WrappedComponent = {
        component: asyncComponent,
        userData: args.userData,
        conditions: conditions?.length ? conditions : undefined,
        props: args.props && Object.keys(args.props).length ? args.props : {}
    }

    Object.defineProperty(wrapped, '_sveltesparouter', {
        value: true,
        writable: false,
        enumerable: false,
        configurable: false
    })

    return wrapped
}
